import json, sys
data = json.load(sys.stdin)
with open('after-cpm-packages.json', 'w') as f:
    json.dump(data, f, indent=2)
print('Saved successfully')
# Compare with baseline
with open('baseline-packages-captured.json') as f:
    baseline = json.load(f)

print('\n=== COMPARISON ===')
# Build lookup: project_name -> framework -> {pkg: version}
def build_lookup(d):
    lookup = {}
    for p in d['projects']:
        name = p['path'].split('/')[-1]
        lookup[name] = {}
        for fw in p['frameworks']:
            tfm = fw['framework']
            lookup[name][tfm] = {}
            for pkg in fw.get('topLevelPackages', []):
                lookup[name][tfm][pkg['id']] = pkg['resolvedVersion']
    return lookup

bl = build_lookup(baseline)
al = build_lookup(data)

changes = []
unchanged = []
for proj in sorted(set(list(bl.keys()) + list(al.keys()))):
    for tfm in sorted(set(list(bl.get(proj,{}).keys()) + list(al.get(proj,{}).keys()))):
        bp = bl.get(proj,{}).get(tfm,{})
        ap = al.get(proj,{}).get(tfm,{})
        for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
            bv = bp.get(pkg, '-')
            av = ap.get(pkg, '-')
            if bv != av:
                changes.append((proj, tfm, pkg, bv, av))
            else:
                unchanged.append((proj, tfm, pkg, bv))

print(f'\nChanges: {len(changes)}')
for c in changes:
    print(f'  {c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]}')

print(f'\nUnchanged: {len(unchanged)}')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}): {u[2]} {u[3]}')
"

